import React, { useState } from 'react';
import { getAgents, createAgent, updateAgent, suspendUser, unsuspendUser, resetAgentPasswordByAdmin, getNextUsername, cleanupWorkflowSeedData } from '../../api';
import AgentPermissionModal from './AgentPermissionModal';

function AgentAdminView() {
  const [agents, setAgents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showViewModal, setShowViewModal] = useState(false);
  const [showPermissionModal, setShowPermissionModal] = useState(false);
  const [selectedAgent, setSelectedAgent] = useState(null);

  const [newAgent, setNewAgent] = useState({ username: '', phoneNumber: '', password: '', agentPrefix: '' });
  const [editForm, setEditForm] = useState({ id: '', phoneNumber: '', password: '', agentBillingRate: '', agentBillingStatus: 'paid' });
  const [error, setError] = useState(null);
  const [creatorFilter, setCreatorFilter] = useState('all'); // 'all', 'admin', 'master_agent'
  const [cleanupLoading, setCleanupLoading] = useState(false);
  const currentRole = String(localStorage.getItem('userRole') || '').toLowerCase();

  const filteredAgents = agents.filter(agent => {
    if (creatorFilter === 'all') return true;
    if (creatorFilter === 'admin') return agent.createdByModel === 'Admin';
    if (creatorFilter === 'master_agent') return agent.createdByModel === 'Agent';
    return true;
  });

  const formatMoney = (value) => {
    if (value === null || value === undefined || value === '') return '—';
    const num = Number(value);
    if (Number.isNaN(num)) return '—';
    return `$${Math.round(num)}`;
  };

  React.useEffect(() => {
    fetchAgents();
  }, []);

  const fetchAgents = async () => {
    try {
      const token = localStorage.getItem('token');
      if (!token) return;
      const data = await getAgents(token);
      setAgents(data || []);
      setError(null);
    } catch (error) {
      console.error('Failed to fetch agents:', error);
      setError(error.message || 'Failed to fetch agents');
    } finally {
      setLoading(false);
    }
  };

  const handlePrefixChange = async (prefix) => {
    const formatted = prefix.toUpperCase();
    setNewAgent(prev => ({ ...prev, agentPrefix: formatted }));

    if (formatted.length >= 2) {
      const token = localStorage.getItem('token');
      // SuperAgent creation always gets 'MA' suffix in this view
      try {
        const { nextUsername } = await getNextUsername(formatted, token, { suffix: 'MA', type: 'agent' });
        setNewAgent(prev => ({ ...prev, username: nextUsername }));
      } catch (err) {
        console.error('Failed to get next username from prefix:', err);
      }
    } else {
      setNewAgent(prev => ({ ...prev, username: '' }));
    }
  };

  const handleCreateAgent = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('token');
      if (!token) throw new Error('No token found');

      // Create agent - explicitly backend sets role: 'master_agent'
      const result = await createAgent(newAgent, token);
      alert(result?.assigned ? 'Master Agent assigned successfully' : 'Master Agent created successfully');
      setShowAddModal(false);
      setNewAgent({ username: '', phoneNumber: '', password: '', agentPrefix: '' });
      fetchAgents();
    } catch (error) {
      console.error('Agent creation error:', error);
      alert('Failed to create agent: ' + error.message);
    }
  };

  const handleToggleStatus = async (agent) => {
    const isSuspended = agent.status === 'suspended';
    const action = isSuspended ? 'unsuspend' : 'suspend';

    if (!window.confirm(`Are you sure you want to ${action} ${agent.username}?`)) return;

    try {
      const token = localStorage.getItem('token');

      if (isSuspended) {
        await unsuspendUser(agent.id, token);
      } else {
        await suspendUser(agent.id, token);
      }
      fetchAgents();
    } catch (error) {
      alert(`Failed to ${action} agent: ` + error.message);
    }
  };

  const openEditModal = (agent) => {
    setEditForm({
      id: agent.id,
      phoneNumber: agent.phoneNumber || '',
      password: '', // Don't show existing hash
      agentBillingRate: agent.agentBillingRate ?? '',
      agentBillingStatus: agent.agentBillingStatus || 'paid',
      unlimitedBalance: agent.unlimitedBalance || false
    });
    setSelectedAgent(agent);
    setShowEditModal(true);
  };

  // Placeholder update function - currently we don't have a specific "updateAgent" endpoint, 
  // but we can add it later. For now, we will simulate or just log.
  const handleUpdateAgent = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('token');
      if (!token) throw new Error('No token found');

      const updateData = { phoneNumber: editForm.phoneNumber, agentBillingRate: editForm.agentBillingRate, agentBillingStatus: editForm.agentBillingStatus, unlimitedBalance: editForm.unlimitedBalance };
      if (editForm.password) updateData.password = editForm.password;

      await updateAgent(editForm.id, updateData, token);
      alert('Agent updated successfully');
      setShowEditModal(false);
      fetchAgents();
    } catch (error) {
      console.error('Update Error:', error);
      alert('Failed to update agent: ' + error.message);
    }
  };

  const openViewModal = (agent) => {
    setSelectedAgent(agent);
    setShowViewModal(true);
  };

  const handleAdjustBalance = async (agent) => {
    const agentId = agent.id;
    const currentBalance = agent.balance ?? 0;
    const input = window.prompt('Enter new agent balance:', `${currentBalance}`);
    if (input === null) return;
    const nextBalance = Number(input);
    if (Number.isNaN(nextBalance)) {
      alert('Balance must be a valid number.');
      return;
    }

    try {
      const token = localStorage.getItem('token');
      if (!token) throw new Error('No token found');

      await updateAgent(agentId, { balance: nextBalance }, token);
      fetchAgents();
    } catch (err) {
      alert('Failed to update agent balance: ' + (err.message || 'Unknown error'));
    }
  };

  const handleResetPassword = async (agent) => {
    const agentId = agent.id;
    const newPassword = window.prompt(`Enter new password for agent ${agent.username}:`, '');

    if (newPassword === null) return;

    if (newPassword.length < 6) {
      alert('Password must be at least 6 characters long');
      return;
    }

    try {
      const token = localStorage.getItem('token');
      if (!token) throw new Error('No token found');

      await resetAgentPasswordByAdmin(agentId, newPassword, token);
      alert(`Password for agent ${agent.username} has been reset successfully.`);
    } catch (err) {
      console.error('Agent password reset failed:', err);
      alert(err.message || 'Failed to reset agent password');
    }
  };

  const handleCleanupWorkflowSeed = async () => {
    const accepted = window.confirm(
      'Delete all seeded workflow demo users and agents now?\n\nThis removes demo hierarchy records created for workflow testing.'
    );
    if (!accepted) return;

    try {
      setCleanupLoading(true);
      const token = localStorage.getItem('token');
      if (!token) throw new Error('No token found');

      const result = await cleanupWorkflowSeedData(token);
      const summary = result?.summary || {};
      alert(
        `Seeded demo data deleted.\nUsers: ${summary.usersDeleted || 0}\nAgents: ${summary.agentsDeleted || 0}\nMaster links: ${summary.masterAgentLinksDeleted || 0}`
      );
      await fetchAgents();
    } catch (err) {
      alert('Failed to delete demo workflow data: ' + (err.message || 'Unknown error'));
    } finally {
      setCleanupLoading(false);
    }
  };

  return (
    <div className="admin-view">
      <div className="view-header">
        <h2>Master Agent Administration</h2>
        <div style={{ display: 'flex', gap: '1rem', alignItems: 'center', flexWrap: 'wrap', justifyContent: 'flex-end' }}>
          <select
            value={creatorFilter}
            onChange={(e) => setCreatorFilter(e.target.value)}
            style={{ padding: '0.5rem', borderRadius: '4px', border: '1px solid #444', backgroundColor: '#333', color: 'white' }}
          >
            <option value="all">Show All Creators</option>
            <option value="admin">Created by Admin</option>
            <option value="master_agent">Created by Master Agent</option>
          </select>
          {currentRole === 'admin' && (
            <button
              className="btn-secondary"
              onClick={handleCleanupWorkflowSeed}
              disabled={cleanupLoading}
              title="Delete workflow demo accounts"
            >
              {cleanupLoading ? 'Deleting Demo Data...' : 'Delete Demo Data'}
            </button>
          )}
          <button className="btn-primary" onClick={() => setShowAddModal(true)}>Add Master Agent</button>
        </div>
      </div>

      {/* CREATE MODAL */}
      {showAddModal && (
        <div className="modal-overlay">
          <div className="modal-content">
            <h3>New Master Agent</h3>
            <form onSubmit={handleCreateAgent}>
              <div className="form-group">
                <label>Prefix</label>
                <input
                  type="text"
                  value={newAgent.agentPrefix}
                  onChange={e => handlePrefixChange(e.target.value)}
                  placeholder="Enter prefix"
                  maxLength={5}
                  required
                />
              </div>
              <div className="form-group">
                <label>Username</label>
                <input type="text" value={newAgent.username} readOnly style={{ background: '#222', color: '#888' }} />
              </div>
              <div className="form-group">
                <label>Phone Number</label>
                <input type="tel" value={newAgent.phoneNumber} onChange={e => setNewAgent({ ...newAgent, phoneNumber: e.target.value })} required />
              </div>
              <div className="form-group">
                <label>Password</label>
                <input type="password" value={newAgent.password} onChange={e => setNewAgent({ ...newAgent, password: e.target.value })} required />
              </div>
              <div className="modal-actions">
                <button type="submit" className="btn-primary">Create</button>
                <button type="button" className="btn-secondary" onClick={() => setShowAddModal(false)}>Cancel</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* EDIT MODAL */}
      {showEditModal && (
        <div className="modal-overlay">
          <div className="modal-content">
            <h3>Edit Agent: {selectedAgent?.username}</h3>
            <form onSubmit={handleUpdateAgent}>
              <div className="form-group">
                <label>Phone Number</label>
                <input type="tel" value={editForm.phoneNumber} onChange={e => setEditForm({ ...editForm, phoneNumber: e.target.value })} required />
              </div>
              <div className="form-group">
                <label>New Password (leave blank to keep)</label>
                <input type="password" value={editForm.password} onChange={e => setEditForm({ ...editForm, password: e.target.value })} />
              </div>
              <div className="form-group">
                <label>Rate per Customer (Weekly)</label>
                <input
                  type="number"
                  min="0"
                  value={editForm.agentBillingRate}
                  onChange={e => setEditForm({ ...editForm, agentBillingRate: e.target.value })}
                />
              </div>
              <div className="form-group">
                <label>Billing Status</label>
                <select
                  value={editForm.agentBillingStatus}
                  onChange={e => setEditForm({ ...editForm, agentBillingStatus: e.target.value })}
                  style={{ width: '100%', padding: '0.5rem', background: '#333', border: '1px solid #444', color: '#fff', borderRadius: '4px' }}
                >
                  <option value="paid">Paid</option>
                  <option value="unpaid">Unpaid</option>
                </select>
              </div>
              <div className="form-group">
                <label style={{ display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer' }}>
                  <input
                    type="checkbox"
                    checked={editForm.unlimitedBalance}
                    onChange={e => setEditForm({ ...editForm, unlimitedBalance: e.target.checked })}
                    style={{ width: 'auto' }}
                  />
                  Unlimited Balance
                </label>
                <small style={{ color: '#aaa', fontSize: '11px' }}>When enabled, this agent can credit players without balance restrictions</small>
              </div>
              <div className="modal-actions">
                <button type="submit" className="btn-primary">Save Changes</button>
                <button type="button" className="btn-secondary" onClick={() => setShowEditModal(false)}>Cancel</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* VIEW MODAL */}
      {showViewModal && selectedAgent && (
        <div className="modal-overlay">
          <div className="modal-content">
            <h3>Agent Details</h3>
            <div className="detail-row"><label>Username:</label> <span>{selectedAgent.username}</span></div>
            <div className="detail-row"><label>Phone Number:</label> <span>{selectedAgent.phoneNumber}</span></div>
            <div className="detail-row"><label>Status:</label> <span className={`badge ${selectedAgent.status}`}>{selectedAgent.status}</span></div>
            <div className="detail-row"><label>Created By:</label> <span>{selectedAgent.createdBy?.username || 'System'}</span></div>
            <div className="detail-row"><label>Created At:</label> <span>{new Date(selectedAgent.createdAt).toLocaleString()}</span></div>
            <div className="detail-row"><label>Customers:</label> <span>{selectedAgent.userCount}</span></div>
            <div className="detail-row"><label>Active Customers:</label> <span>{selectedAgent.activeCustomerCount || 0}</span></div>
            <div className="detail-row"><label>Balance:</label> <span>{formatMoney(selectedAgent.balance)}</span></div>
            <div className="detail-row"><label>Outstanding Balance:</label> <span>{formatMoney(selectedAgent.balanceOwed)}</span></div>
            <div className="detail-row"><label>Rate per Customer:</label> <span>${Math.round(Number(selectedAgent.agentBillingRate || 0))}</span></div>
            <div className="detail-row"><label>Weekly Charge:</label> <span>${Math.round(Number(selectedAgent.weeklyCharge || 0))}</span></div>
            <div className="detail-row"><label>Billing Status:</label> <span>{selectedAgent.agentBillingStatus || 'paid'}</span></div>
            <div className="detail-row"><label>View Only:</label> <span>{selectedAgent.viewOnly ? 'Yes' : 'No'}</span></div>

            <div className="modal-actions">
              <button type="button" className="btn-secondary" onClick={() => setShowViewModal(false)}>Close</button>
            </div>
          </div>
        </div>
      )}

      {showPermissionModal && selectedAgent && (
        <AgentPermissionModal
          agent={selectedAgent}
          onClose={() => setShowPermissionModal(false)}
          onUpdate={fetchAgents}
        />
      )}

      <div className="view-content">
        <div className="table-container">
          <table className="data-table">
            <thead>
              <tr>
                <th>Agent Name</th>
                <th>Role</th>
                <th>Phone Number</th>
                <th>Status</th>
                <th>Created By</th>
                <th>Sub-Agents</th>
                <th>Total Users</th>
                <th>Balance</th>
                <th>Outstanding</th>
                <th>Rate/Customer</th>
                <th>Weekly Charge</th>
                <th>Billing</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan="14">Loading agents...</td></tr>
              ) : error ? (
                <tr><td colSpan="14">{error}</td></tr>
              ) : filteredAgents.length === 0 ? (
                <tr><td colSpan="14">No agents found matching filter.</td></tr>
              ) : filteredAgents.map(agent => (
                <tr key={agent.id}>
                  <td>{agent.username}</td>
                  <td>
                    <span className={`badge ${agent.role === 'master_agent' ? 'btn-primary' : 'btn-secondary'}`} style={{ fontSize: '0.75rem', textTransform: 'capitalize' }}>
                      {agent.role?.replace('_', ' ') || 'agent'}
                    </span>
                  </td>
                  <td>{agent.phoneNumber}</td>
                  <td><span className={`badge ${agent.status || ''}`}>{agent.status || 'unknown'}</span></td>
                  <td style={{ fontWeight: 'bold', color: agent.createdBy ? '#e67e22' : '#999' }}>
                    {agent.createdBy ? (
                      <>
                        <span style={{ fontSize: '0.8em', color: '#888', marginRight: '4px' }}>
                          [{agent.createdByModel === 'Admin' ? 'Admin' : 'MA'}]
                        </span>
                        {agent.createdBy.username}
                      </>
                    ) : 'System'}
                  </td>
                  <td>{agent.role === 'master_agent' ? (agent.subAgentCount || 0) : '—'}</td>
                  <td>{agent.role === 'master_agent' ? (agent.totalUsersInHierarchy || 0) : (agent.userCount || 0)}</td>
                  <td>{formatMoney(agent.balance)}</td>
                  <td>{formatMoney(agent.balanceOwed)}</td>
                  <td>${Math.round(Number(agent.agentBillingRate || 0))}</td>
                  <td>${Math.round(Number(agent.weeklyCharge || 0))}</td>
                  <td><span className={`badge ${agent.agentBillingStatus === 'unpaid' ? 'warning' : 'active'}`}>{agent.agentBillingStatus || 'paid'}</span></td>
                  <td>
                    <button className="btn-small" onClick={() => openEditModal(agent)}>Edit</button>
                    <button className="btn-small" onClick={() => openViewModal(agent)}>View</button>
                    <button className="btn-small" onClick={() => {
                      setSelectedAgent(agent);
                      setShowPermissionModal(true);
                    }}>Permissions</button>
                    <button className="btn-small" onClick={() => handleAdjustBalance(agent)}>Adjust Balance</button>
                    <button
                      className={`btn-small ${agent.status === 'suspended' ? 'btn-success' : 'btn-danger'}`}
                      onClick={() => handleToggleStatus(agent)}
                    >
                      {agent.status === 'suspended' ? 'Activate' : 'Deactivate'}
                    </button>
                    <button className="btn-small btn-secondary" onClick={() => handleResetPassword(agent)}>Reset Pass</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <style>{`
        .modal-overlay {
            position: fixed; top: 0; left: 0; right: 0; bottom: 0;
            background: rgba(0,0,0,0.7); display: flex; justify-content: center; align-items: center; z-index: 1000;
        }
        .modal-content {
            background: #1e1e1e; padding: 2rem; border-radius: 8px; width: min(400px, calc(100vw - 24px)); border: 1px solid #333; color: #fff; max-height: calc(100vh - 32px); overflow-y: auto;
        }
        .form-group { margin-bottom: 1rem; }
        .form-group label { display: block; margin-bottom: 0.5rem; color: #aaa; }
        .form-group input { width: 100%; padding: 0.5rem; background: #333; border: 1px solid #444; color: #fff; border-radius: 4px; }
        .modal-actions { display: flex; gap: 1rem; margin-top: 1.5rem; flex-wrap: wrap; }
        .detail-row { display: flex; justify-content: space-between; padding: 0.5rem 0; border-bottom: 1px solid #333; }
        .detail-row label { color: #888; }
        .btn-success { background-color: #27ae60 !important; }
        @media (max-width: 768px) {
          .modal-content {
            padding: 1rem;
            border-radius: 10px;
          }
          .modal-actions {
            flex-direction: column;
          }
          .modal-actions button {
            width: 100%;
          }
          .table-container .btn-small {
            width: 100%;
            margin-bottom: 6px;
          }
        }
      `}</style>
    </div>
  );
}

export default AgentAdminView;
